function applyTheme(themeId: ThemeId) {
  const root = document.documentElement;
  const isDefault = themeId === "default";

  if (isDefault) {
    root.removeAttribute("data-design-theme");
  } else {
    root.setAttribute("data-design-theme", themeId);
  }

  removeThemeCssLink();
}

function getStoredDesignTheme(): ThemeId {
  if (typeof window === "undefined") {
    return DEFAULT_DESIGN_THEME;
  }

  const stored = window.localStorage.getItem(DESIGN_THEME_STORAGE_KEY);

  return isDesignThemeId(stored) ? stored : DEFAULT_DESIGN_THEME;
}

async function loadThemes() {
  const [defaultTheme, theme] = await Promise.all([
    fs.readFile(
      path.join(import.meta.dirname, "../../../node_modules/tailwindcss/theme.css"),
      "utf-8",
    ),
    fs.readFile(path.join(import.meta.dirname, "./variables.css"), "utf-8"),
  ])
  return { defaultTheme, theme }
}

